import math
class Solution:
    def countTriples(self, n):
        count = 0
        for a in range(1, n + 1):
            for b in range(a, n + 1):
                s = a * a + b * b
                r = math.isqrt(s)
                if r * r == s and r <= n:
                    count += 2
        return count

