var countTriples = function(n) {
    const isSquares = new Set();
    for (let i = 1; i <= n; i++) isSquares.add(i * i);
    let count = 0;
    for (let a = 1; a <= n; a++) {
        for (let b = a; b <= n; b++) {
            if (isSquares.has(a * a + b * b)) count += 2;
        }
    }
    return count;
};
